#include <bits/stdc++.h>

using namespace std;

typedef long long ll;
typedef vector < ll > vl;

// Function to solve the problem for each test case
void solve() {
    ll numRooms, numVisits;
    cin >> numRooms >> numVisits;

    // Array to hold the room visit sequence
    vector < int > visitOrder(numVisits);
    for (int i = 0; i < numVisits; i++) {
        cin >> visitOrder[i];
    }

    // Vector of vectors to hold the volumes of lemonade bottles in each room
    vector < vl > rooms(numRooms);
    for (int i = 0; i < numRooms; i++) {
        int numBottles;
        cin >> numBottles;
        vl volumes(numBottles);

        for (int j = 0; j < numBottles; j++) {
            cin >> volumes[j];
        }

        // Sort the volumes in descending order for easy access to the largest
        sort(volumes.begin(), volumes.end(), greater < ll > ());
        rooms[i] = volumes;
    }

    ll totalLemonade = 0; // Total volume of lemonade drunk
    for (int i = 0; i < numVisits; i++) {
        int roomIndex = visitOrder[i];

        // Check if the room has any bottles left
        if (!rooms[roomIndex].empty()) {
            totalLemonade += rooms[roomIndex][0]; // Drink the largest bottle
            rooms[roomIndex].erase(rooms[roomIndex].begin()); // Remove the drunk bottle
        }
    }

    cout << totalLemonade << endl; // Output the total volume drunk for this test case
}

int main() {
    ios::sync_with_stdio(0);
    cin.tie(0);

    ll testCases;
    cin >> testCases;
    while (testCases--) {
        solve(); // Solve each test case
    }

    return 0;
}

