#include <stdio.h>

#include <stdlib.h>

typedef long long ll;

// Function to compare two long long integers (for sorting)
int compare(const void * a,
    const void * b) {
    return ( * (ll * ) b - * (ll * ) a); // Sorting in descending order
}

// Function to solve the problem for each test case
void solve() {
    ll numRooms, numVisits;
    scanf("%lld %lld", & numRooms, & numVisits); // Read number of rooms and visits

    // Array to hold the room visit sequence
    int * visitOrder = (int * ) malloc(numVisits * sizeof(int));
    for (ll i = 0; i < numVisits; i++) {
        scanf("%d", & visitOrder[i]); // Read the visit order
    }

    // Array of pointers to hold the volumes of lemonade bottles in each room
    ll ** rooms = (ll ** ) malloc(numRooms * sizeof(ll * ));
    int * bottleCounts = (int * ) malloc(numRooms * sizeof(int)); // To keep track of bottle counts

    for (ll i = 0; i < numRooms; i++) {
        scanf("%d", & bottleCounts[i]); // Read the number of bottles
        rooms[i] = (ll * ) malloc(bottleCounts[i] * sizeof(ll)); // Allocate memory for bottles

        for (int j = 0; j < bottleCounts[i]; j++) {
            scanf("%lld", & rooms[i][j]); // Read bottle volumes
        }

        // Sort the volumes in descending order
        qsort(rooms[i], bottleCounts[i], sizeof(ll), compare);
    }

    ll totalLemonade = 0; // Total volume of lemonade drunk
    for (ll i = 0; i < numVisits; i++) {
        int roomIndex = visitOrder[i]; // Get the room index

        // Check if the room has any bottles left
        if (bottleCounts[roomIndex] > 0) {
            totalLemonade += rooms[roomIndex][0]; // Drink the largest bottle
            // Shift all bottles to remove the drunk bottle
            for (int k = 1; k < bottleCounts[roomIndex]; k++) {
                rooms[roomIndex][k - 1] = rooms[roomIndex][k]; // Shift volumes
            }
            bottleCounts[roomIndex]--; // Decrease the bottle count
        }
    }

    printf("%lld\n", totalLemonade); // Output the total volume drunk for this test case

    // Free allocated memory
    for (ll i = 0; i < numRooms; i++) {
        free(rooms[i]);
    }
    free(rooms);
    free(visitOrder);
    free(bottleCounts);
}

int main() {
    ll testCases;
    scanf("%lld", & testCases); // Read number of test cases
    while (testCases--) {
        solve(); // Solve each test case
    }
    return 0;
}

