import java.util.*;
import java.lang.*;
import java.io.*;

class LittleElephantAndLemonade
{
    public static void main(String[] args) throws java.lang.Exception
    {
        Scanner scanner = new Scanner(System.in);
        int testCases = scanner.nextInt(); // Number of test cases
        while (testCases-- > 0) {
            int numRooms = scanner.nextInt(); // Number of rooms
            int numVisits = scanner.nextInt(); // Number of visits

            int[] roomVisits = new int[numVisits]; // Array for room visits
            for (int i = 0; i < numVisits; i++) {
                roomVisits[i] = scanner.nextInt(); // Read room visit
            }

            int[][] bottlesInRooms = new int[numRooms][]; // Array of bottles in each room
            for (int i = 0; i < numRooms; i++) {
                int numBottles = scanner.nextInt(); // Number of bottles in room i
                bottlesInRooms[i] = new int[numBottles]; // Initialize bottles array
                for (int j = 0; j < numBottles; j++) {
                    bottlesInRooms[i][j] = scanner.nextInt(); // Read volumes of bottles
                }
                Arrays.sort(bottlesInRooms[i]); // Sort bottles in ascending order
            }

            int totalLemonadeVolume = 0; // Total volume of lemonade drunk
            for (int i = 0; i < numVisits; i++) {
                int visitedRoom = roomVisits[i]; // Room being visited
                if (bottlesInRooms[visitedRoom].length > 0) {
                    int maxLemonadeVolume = bottlesInRooms[visitedRoom][bottlesInRooms[visitedRoom].length - 1]; // Maximum volume in the room
                    totalLemonadeVolume += maxLemonadeVolume; // Add to total volume
                    bottlesInRooms[visitedRoom] = Arrays.copyOf(bottlesInRooms[visitedRoom], bottlesInRooms[visitedRoom].length - 1); // Remove the bottle
                }
            }
            System.out.println(totalLemonadeVolume); // Output the total volume for the test case
        }
        scanner.close(); // Close the scanner
    }
}
